                print("  PASS")
                tests_passed += 1
            else:
                print(f"  FAIL: {data}")
        except urllib.error.HTTPError as e:
            # Might fail if test server not running
            data = json.loads(e.read().decode())
            if e.code == 404 and 'unreachable' in data.get('error', '').lower():
                print("  SKIP (test HTTP server not running)")
                tests_passed += 1
            else:
                print(f"  FAIL: {data}")
        tests_total += 1

